sp_theme.css_variables:
:root {

  /* Brand — Primary Blues */
  --wrm-blue-50: #EBF3FD;
  --wrm-blue-100: #C2D9F7;
  --wrm-blue-300: #5A9FE8;
  --wrm-blue-500: #1A6DC5;
  --wrm-blue-700: #0E4A8C;
  --wrm-blue-900: #05213F;

  /* Neutral — Grays */
  --wrm-gray-50: #F5F6F8;
  --wrm-gray-100: #E6E8EC;
  --wrm-gray-200: #CDD1D9;
  --wrm-gray-400: #8E95A3;
  --wrm-gray-600: #505869;
  --wrm-gray-800: #2C3140;
  --wrm-gray-900: #171A22;

  /* Semantic — Status */
  --wrm-success: #1A8A5A;
  --wrm-success-bg: #E6F5EF;
  --wrm-warning: #B06A10;
  --wrm-warning-bg: #FDF3E3;
  --wrm-danger: #C0392B;
  --wrm-danger-bg: #FDECEA;
  --wrm-info: #1A6DC5;
  --wrm-info-bg: #EBF3FD;

  /* Surfaces — Light Mode */
  --wrm-surface-page: #F0F2F6;
  --wrm-surface-card: #FFFFFF;
  --wrm-surface-raised: #FFFFFF;
  --wrm-surface-overlay: rgba(23,26,34,0.48);

  /* Surfaces — Dark Mode */
  --wrm-dark-page: #0D1017;
  --wrm-dark-card: #161B26;
  --wrm-dark-raised: #1F2637;
  --wrm-dark-overlay: rgba(0,0,0,0.6);

  /* Text */
  --wrm-text-primary: #171A22;
  --wrm-text-secondary: #505869;
  --wrm-text-muted: #8E95A3;
  --wrm-text-on-dark: #EEF0F5;
  --wrm-text-link: #1A6DC5;

  /* Borders */
  --wrm-border-light: #E6E8EC;
  --wrm-border-default: #CDD1D9;
  --wrm-border-strong: #8E95A3;
  --wrm-border-focus: #1A6DC5;

  /* Spacing */
  --wrm-space-xs: 4px;
  --wrm-space-sm: 8px;
  --wrm-space-md: 16px;
  --wrm-space-lg: 24px;
  --wrm-space-xl: 40px;
  --wrm-space-2xl: 64px;

  /* Border Radius */
  --wrm-radius-sm: 4px;
  --wrm-radius-md: 8px;
  --wrm-radius-lg: 12px;
  --wrm-radius-xl: 20px;
  --wrm-radius-full: 9999px;

  /* Typography */
  --wrm-font-sans: 'Inter', 'Segoe UI', sans-serif;
  --wrm-font-mono: 'JetBrains Mono', monospace;
  --wrm-text-xs: 11px;
  --wrm-text-sm: 13px;
  --wrm-text-base: 15px;
  --wrm-text-lg: 18px;
  --wrm-text-xl: 22px;
  --wrm-text-2xl: 28px;

  /* Elevation / Shadows */
  --wrm-shadow-sm: 0 1px 3px rgba(23,26,34,0.08);
  --wrm-shadow-md: 0 4px 12px rgba(23,26,34,0.12);
  --wrm-shadow-lg: 0 8px 24px rgba(23,26,34,0.16);

  /* Transitions */
  --wrm-ease: cubic-bezier(0.4,0,0.2,1);
  --wrm-duration-fast: 120ms;
  --wrm-duration-base: 200ms;
  --wrm-duration-slow: 350ms;

  /* Z-index Scale */
  --wrm-z-dropdown: 100;
  --wrm-z-sticky: 200;
  --wrm-z-overlay: 300;
  --wrm-z-modal: 400;
  --wrm-z-toast: --wrm-z-toast: 500;

  /* Dark mode overrides */
}

@media (prefers-color-scheme: dark) {
  :root {
    --wrm-surface-page:    var(--wrm-dark-page);
    --wrm-surface-card:    var(--wrm-dark-card);
    --wrm-surface-raised:  var(--wrm-dark-raised);
    --wrm-text-primary:    var(--wrm-text-on-dark);
    --wrm-text-secondary:  var(--wrm-gray-400);
    --wrm-text-muted:      var(--wrm-gray-600);
    --wrm-border-light:    rgba(255,255,255,0.06);
    --wrm-border-default:  rgba(255,255,255,0.12);
    --wrm-border-strong:   rgba(255,255,255,0.24);
    --wrm-blue-500:        #4A9EE8;
    --wrm-text-link:       #4A9EE8;
  }
}
